if (profile.height != null && profile.height > 0) data["height"] = profile.height if (profile.age != null && profile.age > 0) data["age"] = profile.age if (!profile.gender.isNullOrBlank()) data["gender"] = profile.gender if (!profile.activityLevel.isNullOrBlank()) data["activityLevel"] = profile.activityLevel if (!profile.experience.isNullOrBlank()) data["experience"] = profile.experience if (!profile.bodyFat.isNullOrBlank()) data["bodyFat"] = profile.bodyFat if (!profile.nutritionStyle.isNullOrBlank()) data["nutritionStyle"] = profile.nutritionStyle if (!profile.sleepHours.isNullOrBlank()) data["sleepHours"] = profile.sleepHours
try { if (batch != null) { batch.set(resolvedRef, data, SetOptions.merge()) } else { com.example.myapplication.persistence.FirestoreHelper.withRetry { resolvedRef.set(data, SetOptions.merge()).await() } } } catch (e: Exception) { Log.e("UserProfileManager", "❌ Error saving profile", e) } }
