fun documentToUserProfile(doc: com.google.firebase.firestore.DocumentSnapshot, email: String): UserProfile { val username = doc.getString(KEY_USERNAME) ?: "" val firstName = doc.getString(KEY_FIRST_NAME) ?: "" val lastName = doc.getString(KEY_LAST_NAME) ?: "" val address = doc.getString(KEY_ADDRESS) ?: "" val xp = (doc.get(KEY_XP) as? Number)?.toInt() ?: 0 val followers = (doc.get(KEY_FOLLOWERS) as? Number)?.toInt() ?: 0 val following = (doc.get(KEY_FOLLOWING) as? Number)?.toInt() ?: 0 val badges = when (val b = doc.get(KEY_BADGES)) { is List<*> -> b.filterIsInstance<String>() is String -> b.split(',').filter { it.isNotBlank() } else -> emptyList() } val streakFreezes = (doc.get("streak_freezes") as? Number)?.toInt() ?: 0 val equipment = when (val eq = doc.get(KEY_EQUIPMENT)) { is List<*> -> eq.filterIsInstance<String>() is String -> eq.split(',').filter { it.isNotBlank() } else -> emptyList() } val focusAreas = when (val fa = doc.get("focusAreas")) { is List<*> -> fa.filterIsInstance<String>() is String -> fa.split(',').filter { it.isNotBlank() } else -> emptyList() } val workoutGoal = doc.getString("workoutGoal") ?: "" val weightUnit = doc.getString(KEY_WEIGHT_UNIT) ?: "kg" val speedUnit = doc.getString(KEY_SPEED_UNIT) ?: "km/h" val startOfWeek = doc.getString(KEY_START_OF_WEEK) ?: "Monday" val quietHoursStart = doc.getString(KEY_QUIET_HOURS_START) ?: "22:00" val quietHoursEnd = doc.getString(KEY_QUIET_HOURS_END) ?: "07:00" val muteStreakReminders = doc.getBoolean(KEY_MUTE_STREAK) ?: false val detailedCalories = doc.getBoolean("detailed_calories") ?: false val isPublic = doc.getBoolean(KEY_IS_PUBLIC) ?: false val showLevel = doc.getBoolean(KEY_SHOW_LEVEL) ?: false val showBadges = doc.getBoolean(KEY_SHOW_BADGES) ?: false val showStreak = doc.getBoolean(KEY_SHOW_STREAK) ?: false val showPlanPath = doc.getBoolean(KEY_SHOW_PLAN_PATH) ?: false val showChallenges = doc.getBoolean(KEY_SHOW_CHALLENGES) ?: false val showFollowers = doc.getBoolean(KEY_SHOW_FOLLOWERS) ?: false val shareActivities = doc.getBoolean(KEY_SHARE_ACTIVITIES) ?: false val totalWorkouts = (doc.get("total_workouts_completed") as? Number)?.toInt() ?: 0 val totalCalories = (doc.get(KEY_TOTAL_CALORIES) as? Number)?.toDouble() ?: 0.0 val earlyBird = (doc.get(KEY_EARLY_BIRD) as? Number)?.toInt() ?: 0 val nightOwl = (doc.get(KEY_NIGHT_OWL) as? Number)?.toInt() ?: 0 val loginStreak = (doc.get("streak_days") as? Number)?.toInt() ?: 0 val lastLogin = doc.getString(KEY_LAST_LOGIN) val totalPlans = (doc.get(KEY_TOTAL_PLANS) as? Number)?.toInt() ?: 0 val profilePictureUrl = doc.getString(KEY_PROFILE_PICTURE) val height = (doc.get("height") as? Number)?.toDouble() val age = (doc.get("age") as? Number)?.toInt() val gender = doc.getString("gender") val activityLevel = doc.getString("activityLevel") val experience = doc.getString("experience") val bodyFat = doc.getString("bodyFat") val limitations = when (val lim = doc.get("limitations")) { is List<*> -> lim.filterIsInstance<String>() is String -> lim.split(',').filter { it.isNotBlank() } else -> emptyList() } val nutritionStyle = doc.getString("nutritionStyle") val sleepHours = doc.getString("sleepHours") return UserProfile( username = username, email = email, firstName = firstName, lastName = lastName, address = address, xp = xp, followers = followers, following = following, badges = badges, streakFreezes = streakFreezes, equipment = equipment, focusAreas = focusAreas, workoutGoal = workoutGoal, weightUnit = weightUnit, speedUnit = speedUnit, startOfWeek = startOfWeek, quietHoursStart = quietHoursStart, quietHoursEnd = quietHoursEnd, muteStreakReminders = muteStreakReminders, detailedCalories = detailedCalories, isPublicProfile = isPublic, showLevel = showLevel, showBadges = showBadges, showStreak = showStreak, showPlanPath = showPlanPath, showChallenges = showChallenges, showFollowers = showFollowers, shareActivities = shareActivities, totalWorkoutsCompleted = totalWorkouts, totalCaloriesBurned = totalCalories, earlyBirdWorkouts = earlyBird, nightOwlWorkouts = nightOwl, currentLoginStreak = loginStreak, lastLoginDate = lastLogin, totalPlansCreated = totalPlans, profilePictureUrl = profilePictureUrl, height = height, age = age, gender = gender, activityLevel = activityLevel, experience = experience, bodyFat = bodyFat, limitations = limitations, nutritionStyle = nutritionStyle, sleepHours = sleepHours ) }
suspend fun saveWorkoutStats( email: String, streak: Int, totalWorkouts: Int, weeklyDone: Int, lastWorkoutEpoch: Long, planDay: Int = 1, weeklyTarget: Int = 0, batch: com.google.firebase.firestore.WriteBatch? = null ) { val data = mapOf( "streak_days" to streak, "total_workouts_completed" to totalWorkouts, "weekly_done" to weeklyDone, "last_workout_epoch" to lastWorkoutEpoch, "plan_day" to planDay, "weekly_target" to weeklyTarget ) if (batch != null) { batch.set(com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocRef(), data, SetOptions.merge()) } else { com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocRef().set(data, SetOptions.merge()).await() } }
suspend fun getWorkoutStats(email: String): Map<String, Any>? { return try { val doc = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocRef().get().await() if (doc.exists()) { mapOf( "streak_days" to (doc.getLong("streak_days")?.toInt() ?: 0), "total_workouts_completed" to (doc.getLong("total_workouts_completed")?.toInt() ?: 0), "weekly_done" to (doc.getLong("weekly_done")?.toInt() ?: 0), "last_workout_epoch" to (doc.getLong("last_workout_epoch") ?: 0L), "plan_day" to (doc.getLong("plan_day")?.toInt() ?: 1), "weekly_target" to (doc.getLong("weekly_target")?.toInt() ?: 0) ) } else null } catch (e: Exception) { null } }
suspend fun deleteUserData(email: String) { if (email.isBlank()) return val uid = Firebase.auth.currentUser?.uid val db = com.example.myapplication.persistence.FirestoreHelper.getDb() try { val subcollections = listOf( "weightLogs", "dailyLogs", "dailyMetrics", "daily_health", "customMeals", "nutritionPlan", "meal_feedback", "exerciseLogs", "workoutSessions", "xp_history", "activePlan", "runSessions" ) for (sub in subcollections) { try { val docs = db.collection("users").document(email).collection(sub).get().await() for (doc in docs) { doc.reference.delete().await() } } catch(_: Exception) {} } db.collection("users").document(email).delete().await()
if (uid != null && uid != email) { for (sub in subcollections) { try { val docs = db.collection("users").document(uid).collection(sub).get().await() for (doc in docs) { doc.reference.delete().await() } } catch(_: Exception) {} } try { db.collection("users").document(uid).delete().await() } catch (_: Exception) {} }
val resolvedId = com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId() ?: email for (key in setOf(resolvedId, uid, email).filterNotNull()) { try { db.collection("user_plans").document(key).delete().await() } catch (_: Exception) {} } try { for (key in setOf(resolvedId, uid, email).filterNotNull()) { val asDocs = db.collection("follows").whereEqualTo("followerId", key).get().await() for (doc in asDocs) { doc.reference.delete().await() } val bsDocs = db.collection("follows").whereEqualTo("followingId", key).get().await() for (doc in bsDocs) { doc.reference.delete().await() } } } catch (_: Exception) {} } catch (e: Exception) { Log.e("UserProfileManager", "❌ Error deleting user data", e) } }
fun clearAllLocalData() { val prefNames = listOf( "user_prefs", "body_module", "nutrition_xp", "bm_prefs", "smartwatch_prefs", "algorithm_prefs", "weight_widget_prefs", "water_widget_prefs", "food_cache", "water_cache", "burned_cache", "daily_sync_prefs", "streak_widget_prefs" ) for (name in prefNames) { SettingsManager.provider.getSettings(name).clear() } SettingsManager.provider.getSettings("app_flags").putBoolean("fresh_start_on_login", true) Log.d("UserProfileManager", "✅ All local SharedPreferences cleared + fresh_start flag set") } }

package com.example.myapplication.domain.workout

import com.example.myapplication.data.settings.UserPreferencesRepository
import com.example.myapplication.viewmodels.BodyHomeUiState
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import com.example.myapplication.data.UserPreferences
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

class GetBodyMetricsUseCase(private val workoutRepo: WorkoutRepository, private val settingsRepo: UserPreferencesRepository) {
    fun invoke(email: String): Flow<BodyHomeUiState> = flow {
        // Emit loading state initially
        emit(BodyHomeUiState(isLoading = true))

        var state = BodyHomeUiState(isLoading = false)

        try {
            // Firestore Sync: Preberi osvežene podatke in posodobi lokalno bazo
            val stats = UserPreferences.getWorkoutStats(email)
            if (stats != null) {
                val streak = stats["streak_days"] as? Int ?: 0
                val total = stats["total_workouts_completed"] as? Int ?: 0
                val weeklyDone = stats["weekly_done"] as? Int ?: 0
                val weeklyTarget = stats["weekly_target"] as? Int ?: 3
                val planDay = stats["plan_day"] as? Int ?: 1
                val lastEpoch = stats["last_workout_epoch"] as? Long ?: 0L

                val isDoneToday = if (lastEpoch == 0L) false else {
                    val now = Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date
                    val lastDate = kotlinx.datetime.LocalDate.fromEpochDays(lastEpoch.toInt())
                    lastDate == now
                }

                // Sync with local repository
                settingsRepo.updateWorkoutStats(
                    completedDay = planDay,
                    timestamp = if (lastEpoch > 0) lastEpoch * 86400000L else 0L
                )

                state = state.copy(
                    streakDays = streak,
                    weeklyDone = weeklyDone,
                    weeklyTarget = weeklyTarget,
                    planDay = planDay,
                    totalWorkoutsCompleted = total,
                    isWorkoutDoneToday = isDoneToday,
                    dailyKcal = settingsRepo.getDailyCalories().toInt()
                )
            } else {
                // Če ni v Firestore (prvi zagon brez oblaka), preberi začasno to kar imamo preden prepiše vse na null
                // Ker je ta koda tu fallback, uporabimo zasilne vrednosti dokler se ne uredi
                val isDoneLocally = settingsRepo.isWorkoutDoneToday()
                state = state.copy(
                    planDay = settingsRepo.getPlanDay(),
                    weeklyTarget = settingsRepo.getWeeklyTarget(),
                    isWorkoutDoneToday = isDoneLocally,
                    dailyKcal = settingsRepo.getDailyCalories().toInt()
                )
            }
        } catch (e: Exception) {
            state = state.copy(errorMessage = e.message)
        }

        emit(state)
    }
}

