data class ShopState(
    val userXP: Int = 0,
    val streakFreezes: Int = 0,
    val coupons: List<String> = emptyList(),
    val isLoading: Boolean = false
)

class ShopViewModel(app: Application) : AndroidViewModel(app) {

    private val _state = MutableStateFlow(ShopState())
    val state: StateFlow<ShopState> = _state

    private val context = app.applicationContext
    private val currentUserEmail: String
        get() = Firebase.auth.currentUser?.email ?: ""

    init {
        refreshData()
    }

    fun refreshData() {
        val email = currentUserEmail
        if (email.isBlank()) return

        viewModelScope.launch {
            if (email.isNotBlank()) {
                val profile = UserProfileManager.loadProfileFromFirestore(email)
                    ?: UserProfileManager.loadProfile(email)
                _state.value = _state.value.copy(
                    userXP = profile.xp,
                    streakFreezes = profile.streakFreezes
                )
            }
        }
    }

    fun buyStreakFreeze() {
        val email = currentUserEmail
        if (email.isBlank()) return
        if (_state.value.isLoading) return

        viewModelScope.launch(Dispatchers.IO) {
            _state.value = _state.value.copy(isLoading = true)
            try {
                // 1. Load fresh profile
                val profile = UserProfileManager.loadProfileFromFirestore(email)
                    ?: UserProfileManager.loadProfile(email)

                val PRICE = 300
                val MAX_FREEZES = 3

                if (profile.streakFreezes >= MAX_FREEZES) {
                    withContext(Dispatchers.Main) {
                        com.example.myapplication.utils.AppToast.showWarning(context, "Max 3 Streak Freezes allowed!")
                    }
                    return@launch
                }

                if (profile.xp < PRICE) {
                    withContext(Dispatchers.Main) {
                        com.example.myapplication.utils.AppToast.showError(context, "Not enough XP! Need \$PRICE XP.")
                    }
                    return@launch
                }

                // 2. Transaction (Deduct XP, Add Freeze)
                val newXP = profile.xp - PRICE
                val newFreezes = profile.streakFreezes + 1

                val updatedProfile = profile.copy(
                    xp = newXP,
                    streakFreezes = newFreezes
                )

                // Save
                UserProfileManager.saveProfile(updatedProfile)
                UserProfileManager.saveProfileFirestore(updatedProfile)

                // Log XP spend
                try {
                    FirestoreHelper.getCurrentUserDocRef()
                        .collection("xp_history")
                        .add(mapOf(
                            "xp" to -PRICE,
                            "source" to "SHOP_SPEND",
                            "description" to "Bought Streak Freeze",
                            "timestamp" to System.currentTimeMillis()
                        ))
                } catch (_: Exception) {}

                withContext(Dispatchers.Main) {
                     com.example.myapplication.utils.AppToast.showSuccess(context, "Streak Freeze Purchased!")
                }

                // Refresh local state
                _state.value = _state.value.copy(
                    userXP = newXP,
                    streakFreezes = newFreezes
                )

            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    com.example.myapplication.utils.AppToast.showError(context, "Purchase failed: \${e.message}")
                }
            } finally {
                _state.value = _state.value.copy(isLoading = false)
            }
        }
    }

    fun buyCoupon() {
        // Mock implementation for discount
        val email = currentUserEmail
        if (email.isBlank() || _state.value.isLoading) return

        viewModelScope.launch(Dispatchers.IO) {
            _state.value = _state.value.copy(isLoading = true)
            try {
                 val profile = UserProfileManager.loadProfileFromFirestore(email)
                    ?: UserProfileManager.loadProfile(email)

                val PRICE = 500
                if (profile.xp < PRICE) {
                    withContext(Dispatchers.Main) {
                        com.example.myapplication.utils.AppToast.showError(context, "Not enough XP! Need \$PRICE XP.")
                    }
                    return@launch
                }

                // Deduct XP
                val newXP = profile.xp - PRICE
                val updatedProfile = profile.copy(xp = newXP)

                UserProfileManager.saveProfile(updatedProfile)
                UserProfileManager.saveProfileFirestore(updatedProfile)

                // In real app, save coupon to database. Here just a toast.
                 withContext(Dispatchers.Main) {
                     com.example.myapplication.utils.AppToast.showSuccess(context, "Coupon 'PRO10' Unlocked!")
                }

                _state.value = _state.value.copy(userXP = newXP)

            } catch (e: Exception) {
                 withContext(Dispatchers.Main) {
                    com.example.myapplication.utils.AppToast.showError(context, "Purchase failed")
                }
            } finally {
                _state.value = _state.value.copy(isLoading = false)
            }
        }
    }
}

package com.example.myapplication.workers

import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.core.app.NotificationCompat
import androidx.work.CoroutineWorker
import androidx.work.ExistingWorkPolicy
import androidx.work.OneTimeWorkRequestBuilder
import androidx.work.WorkManager
import androidx.work.WorkerParameters
import com.example.myapplication.MainActivity
import com.example.myapplication.data.UserPreferences
import com.google.firebase.auth.ktx.auth
import com.google.firebase.ktx.Firebase
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.LocalTime
import java.util.concurrent.TimeUnit

/**
 * StreakReminderWorker — vsak dan ob 20:00 preveri, ali je vadba opravljena.
 *
 * Logika:
 * - Če je danes REST dan → ne pošlje notifikacije (streak bo +1 avtomatično ob polnoči)
 * - Če je danes WORKOUT dan in je vadba že opravljena → ne pošlje notifikacije
 * - Če je danes WORKOUT dan in vadba NI opravljena → pošlje motivacijsko notifikacijo
 *
 * Motivacijska sporočila se personalizirajo glede na:
 * - Trenutni streak
 * - Cilj (goal) iz plana
 * - Dan v planu
 */
class StreakReminderWorker(
    private val context: Context,
    workerParams: WorkerParameters
) : CoroutineWorker(context, workerParams) {

    private data class ReminderContext(
        val streak: Int,
        val planDay: Int,
        val waterMl: Int,
        val consumedCalories: Int,
        val burnedCalories: Int,
        val streakFreezes: Int,
        val currentHour: Int
    )

    companion object {
        private const val TAG = "StreakReminderWorker"
        private const val WORK_NAME = "streak_reminder_20h"
        const val CHANNEL_ID = "streak_reminder_channel"
        private const val NOTIFICATION_ID = 1001

        /**
         * Načrtuje opomnik za danes ob 20:00.
         * Kliči ob loginu in ob zagonu aplikacije.
         */
        fun scheduleForToday(context: Context) {
            val now = LocalDateTime.now()
            val targetTime = LocalDateTime.of(now.toLocalDate(), LocalTime.of(20, 0))

            // Če je 20:00 danes že minila, načrtuj za jutri ob 20:00
            val finalTarget = if (now.isBefore(targetTime)) targetTime
                             else targetTime.plusDays(1)

            val delayMs = java.time.Duration.between(now, finalTarget).toMillis()
            val delayMinutes = if (delayMs > 0) delayMs / 60000 else 1L

            val request = OneTimeWorkRequestBuilder<StreakReminderWorker>()
                .setInitialDelay(delayMinutes, TimeUnit.MINUTES)
                .build()

            WorkManager.getInstance(context)
                .enqueueUniqueWork(WORK_NAME, ExistingWorkPolicy.REPLACE, request)

            Log.d(TAG, "Scheduled streak reminder in ${delayMinutes}min (at $finalTarget)")
        }

        /**
         * Ustvari notification channel. Kliči ob zagonu aplikacije.
         */
        fun createNotificationChannel(context: Context) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Streak Reminders",
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Daily reminder to complete your workout and keep your streak alive"
                enableVibration(true)
            }
            val manager = context.getSystemService(NotificationManager::class.java)
            manager.createNotificationChannel(channel)
        }
    }

    override suspend fun doWork(): Result {
        // Preveri ali je uporabnik prijavljen
        val currentUser = Firebase.auth.currentUser
        if (currentUser == null || currentUser.email == null) {
            Log.d(TAG, "No user logged in — skipping reminder")
            scheduleForTomorrow()
            return Result.success()
        }

        // Dodano: Preveri nastavitve obvestil (Quiet Hours & Mute)
        val email = currentUser.email.orEmpty()
        val userProfile = UserPreferences.loadProfile(context, email)

        if (userProfile.muteStreakReminders) {
            Log.d(TAG, "User muted streak reminders — skipping")
            scheduleForTomorrow()
            return Result.success()
        }

        // Preveri Quiet hours
        try {
            val now = LocalTime.now()
            val startParts = userProfile.quietHoursStart.split(":")
            val endParts = userProfile.quietHoursEnd.split(":")
            if (startParts.size == 2 && endParts.size == 2) {
                val start = LocalTime.of(startParts[0].toInt(), startParts[1].toInt())
                val end = LocalTime.of(endParts[0].toInt(), endParts[1].toInt())

                val inQuietHours = if (start.isBefore(end)) {
                    now.isAfter(start) && now.isBefore(end)
                } else {
                    now.isAfter(start) || now.isBefore(end)
                }

                if (inQuietHours) {
                    Log.d(TAG, "Current time is within quiet hours (${userProfile.quietHoursStart}-${userProfile.quietHoursEnd}) — skipping reminder")
                    scheduleForTomorrow()
                    return Result.success()
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error parsing quiet hours: ${e.message}")
        }

        val prefs = context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
        val todayIsRest = prefs.getBoolean("today_is_rest", false)
        val lastWorkoutEpoch = prefs.getLong("last_workout_epoch", 0L)
        val workoutDoneToday = if (lastWorkoutEpoch == 0L) false
            else LocalDate.ofEpochDay(lastWorkoutEpoch) == LocalDate.now()
        val currentStreak = prefs.getInt("streak_days", 0)
        val planDay = prefs.getInt("plan_day", 1)
        val reminderContext = loadReminderContext(currentStreak, planDay)

        Log.d(TAG, "Reminder check: todayIsRest=$todayIsRest, workoutDone=$workoutDoneToday, streak=$currentStreak")

        when {
            todayIsRest -> {
                // Rest dan — ni potreben opomnik
                Log.d(TAG, "Today is rest day — no reminder needed")
            }
            workoutDoneToday -> {
                // Vadba že opravljena — pošlji čestitko
                sendCongratulationsNotification(reminderContext)
            }
            else -> {
                // Vadba še ni opravljena — pošlji opomnik
                sendReminderNotification(reminderContext)
            }
        }

        // Načrtuj za jutri ob 20:00
        scheduleForTomorrow()

        return Result.success()
    }

    private fun loadReminderContext(streak: Int, planDay: Int): ReminderContext {
        val dateKey = LocalDate.now().toString()
        val waterMl = context.getSharedPreferences("water_cache", Context.MODE_PRIVATE)
            .getInt("water_$dateKey", 0)
        val consumedCalories = context.getSharedPreferences("calories_cache", Context.MODE_PRIVATE)
            .getInt("calories_$dateKey", 0)
        val burnedCalories = context.getSharedPreferences("burned_cache", Context.MODE_PRIVATE)
            .getInt("burned_$dateKey", 0)

        val email = Firebase.auth.currentUser?.email
        val streakFreezes = if (!email.isNullOrBlank()) {
            runCatching { UserPreferences.loadProfile(context, email).streakFreezes }.getOrDefault(0)
        } else {
            0
        }

        return ReminderContext(
            streak = streak,
            planDay = planDay,
            waterMl = waterMl,
            consumedCalories = consumedCalories,
            burnedCalories = burnedCalories,
            streakFreezes = streakFreezes,
            currentHour = LocalDateTime.now().hour
        )
    }

    private fun sendReminderNotification(ctx: ReminderContext) {
        // A/B test determination based on simple hash of user ID or device time if no user
        val uid = Firebase.auth.currentUser?.uid ?: ""
        val toneVariant = if (uid.isNotEmpty()) Math.abs(uid.hashCode()) % 3 else 0
        Log.d(TAG, "Notification Tone Variant selected: $toneVariant")

        val title = getReminderTitle(ctx, toneVariant)
        val message = getReminderMessage(ctx, toneVariant)

        sendNotification(title, message, isReminder = true)
        Log.d(
            TAG,
            "Sent contextual reminder: streak=${ctx.streak}, water=${ctx.waterMl}, calories=${ctx.consumedCalories}, burned=${ctx.burnedCalories}, freezes=${ctx.streakFreezes}"
        )
    }

    private fun sendCongratulationsNotification(ctx: ReminderContext) {
        val uid = Firebase.auth.currentUser?.uid ?: ""
        val toneVariant = if (uid.isNotEmpty()) Math.abs(uid.hashCode()) % 3 else 0

        val title = " Great job today!"
        val message = when (toneVariant) {
            0 -> when { // Encouraging & Soft
                ctx.streak >= 30 -> "You're on a ${ctx.streak} day streak. So proud of your discipline! "
                ctx.streak >= 14 -> "Two weeks straight (${ctx.streak} days). You're doing amazing! ✨"
                ctx.streak >= 7 -> "One week down (${ctx.streak} days). Keep up the fantastic work! "
                ctx.waterMl < 1200 -> "You did great. Just remember to drink some water to recover better! "
                else -> "Workout done. Pat yourself on the back! "
            }
            1 -> when { // Strict & Coach
                ctx.streak >= 30 -> "Hit ${ctx.streak} days. Elite discipline. No excuses tomorrow. "
                ctx.streak >= 14 -> "14+ days (${ctx.streak}). Don't lose the momentum now. "
                ctx.streak >= 7 -> "7 days down. The real test starts now. Keep pushing. "
                ctx.waterMl < 1200 -> "Mission accomplished, but hydration is weak. Drink water. "
                else -> "Session logged. Get ready for the next one. ️‍♂️"
            }
            else -> when { // Default / Data driven
                ctx.streak >= 30 -> "You're on a ${ctx.streak} day streak and still consistent. Elite discipline. "
                ctx.streak >= 14 -> "Two weeks+ consistency (${ctx.streak} days). Keep this momentum! "
                ctx.streak >= 7 -> "Week streak secured (${ctx.streak} days). Nice execution today. ⭐"
                ctx.waterMl < 1200 -> "Workout done. Add some hydration before sleep to recover better. "
                else -> "Workout done and streak alive. Great finish for today. "
            }
        }

        sendNotification(title, message, isReminder = false)
        Log.d(TAG, "Sent congratulations notification: streak=${ctx.streak}")
    }

    private fun getReminderTitle(ctx: ReminderContext, toneVariant: Int): String {
        val isLate = ctx.currentHour >= 21
        return when (toneVariant) {
            0 -> when { // Encouraging
                 ctx.streak >= 14 && ctx.streakFreezes == 0 -> "Don't break your ${ctx.streak}-day streak! "
                 ctx.waterMl < 600 -> "Let's drink some water! "
                 ctx.consumedCalories < 600 && isLate -> "Time for a small meal! "
                 ctx.streak == 0 -> "Ready to start a new streak? ✨"
                 ctx.streak >= 7 -> "Your ${ctx.streak}-day streak is beautiful! "
                 ctx.streak >= 3 -> "Keep your momentum going! "
                 else -> "You can do this workout! ❤️"
            }
            1 -> when { // Strict Coach
                 ctx.streak >= 14 && ctx.streakFreezes == 0 -> " ${ctx.streak} days at risk. Move!"
                 ctx.waterMl < 600 -> "Hydrate immediately. "
                 ctx.consumedCalories < 600 && isLate -> "Fuel up. No excuses. "
                 ctx.streak == 0 -> "Zero streak. Change that now. ⚡"
                 ctx.streak >= 7 -> "Protect your ${ctx.streak}-day streak or lose it. "
                 ctx.streak >= 3 -> "Don't get lazy now. ⏱️"
                 else -> "Time to work out! Go! ️"
            }
            else -> when { // Default
                ctx.streak >= 14 && ctx.streakFreezes == 0 -> " ${ctx.streak}-day streak at risk"
                ctx.waterMl < 600 -> " Hydrate + train"
                ctx.consumedCalories < 600 && isLate -> "️ Fuel up and finish your workout"
                ctx.streak == 0 -> "⚡ Start your streak today"
                ctx.streak >= 7 -> " Protect your ${ctx.streak}-day streak"
                ctx.streak >= 3 -> "⏱️ Keep the streak alive"
                else -> "️ Time to work out!"
            }
        }
    }

    private fun getReminderMessage(ctx: ReminderContext, toneVariant: Int): String {
        val week = ((ctx.planDay - 1) / 7) + 1
        val dayInWeek = ((ctx.planDay - 1) % 7) + 1
        val dayContext = "Week $week, Day $dayInWeek"

        val freezeContext = if (ctx.streakFreezes > 0) {
            "You still have ${ctx.streakFreezes} streak freeze${if (ctx.streakFreezes == 1) "" else "s"}, but use it only when necessary."
        } else {
            "No streak freeze available today, so this session matters."
        }

        return when (toneVariant) {
            0 -> when { // Extrinsic / Friendly
                ctx.waterMl < 600 -> "Your water intake is quite low (${ctx.waterMl} ml). Please hydrate and then try a quick workout. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "Today is the perfect day to start a new streak. Even 15 min is enough! ($dayContext)"
                else -> "Take some time for yourself today. Your daily workout awaits. ($dayContext)"
            }
            1 -> when { // Intrinsic / Aggressive
                ctx.waterMl < 600 -> "Low hydration (${ctx.waterMl} ml) ruins performance. Drink up and get the work done. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "A streak of 0 isn't progress. Put the work in today. ($dayContext)"
                else -> "Discipline over motivation. Go finish your session. ($dayContext)"
            }
            else -> when { // Default
                ctx.waterMl < 600 -> "Hydration is low (${ctx.waterMl} ml). Drink water first, then finish a short workout. $freezeContext ($dayContext)"
                ctx.consumedCalories < 600 && ctx.currentHour >= 21 -> "You logged only ${ctx.consumedCalories} kcal so far. Add a light meal and complete your session to recover well. $freezeContext ($dayContext)"
                ctx.burnedCalories >= 700 -> "You already burned ${ctx.burnedCalories} kcal today. Great activity - complete the planned workout to lock the streak. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "Start your first streak day now. Even 20 minutes is enough to build momentum. ($dayContext)"
                ctx.streak >= 14 && ctx.streakFreezes == 0 -> "${ctx.streak} days of consistency are on the line. Complete today's workout to protect your run. ($dayContext)"
                ctx.streak >= 7 -> "One week+ streak in progress (${ctx.streak} days). Stay consistent tonight. ($dayContext)"
                ctx.streak >= 3 -> "Good rhythm so far (${ctx.streak} days). One more session keeps the chain going. ($dayContext)"
                else -> "Your daily workout is waiting. Quick session now makes tomorrow easier. ($dayContext)"
            }
        }
    }

    private fun sendNotification(title: String, message: String, isReminder: Boolean) {
        val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager

        // Ustvari channel če ne obstaja
        val channel = NotificationChannel(
            CHANNEL_ID,
            "Streak Reminders",
            NotificationManager.IMPORTANCE_DEFAULT
        ).apply {
            description = "Daily reminder to complete your workout and keep your streak alive"
            enableVibration(true)
        }
        notificationManager.createNotificationChannel(channel)

        // Intent za odprtje aplikacije
        val intent = Intent(context, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        val pendingIntent = PendingIntent.getActivity(
            context, 0, intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        val notification = NotificationCompat.Builder(context, CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_popup_reminder)
            .setContentTitle(title)
            .setContentText(message)
            .setStyle(NotificationCompat.BigTextStyle().bigText(message))
            .setContentIntent(pendingIntent)
            .setAutoCancel(true)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .apply {
                if (isReminder) {
                    setVibrate(longArrayOf(0, 300, 100, 300))
                }
            }
            .build()

        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun scheduleForTomorrow() {
        val now = LocalDateTime.now()
        val tomorrow = now.toLocalDate().plusDays(1)
        val targetDateTime = LocalDateTime.of(tomorrow, LocalTime.of(20, 0))

        val delayMs = java.time.Duration.between(now, targetDateTime).toMillis()
        val delayMinutes = if (delayMs > 0) delayMs / 60000 else 1L

        val request = OneTimeWorkRequestBuilder<StreakReminderWorker>()
            .setInitialDelay(delayMinutes, TimeUnit.MINUTES)
            .build()

        WorkManager.getInstance(context)
            .enqueueUniqueWork(WORK_NAME, ExistingWorkPolicy.REPLACE, request)

        Log.d(TAG, "Scheduled next reminder in ${delayMinutes}min (at $targetDateTime)")
    }
}

package com.example.myapplication.workers

import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.core.app.NotificationCompat
import androidx.work.CoroutineWorker
import androidx.work.ExistingWorkPolicy
import androidx.work.OneTimeWorkRequestBuilder
import androidx.work.WorkManager
import androidx.work.WorkerParameters
import com.example.myapplication.MainActivity
import com.example.myapplication.data.settings.UserProfileManager
import com.example.myapplication.persistence.FirestoreHelper
import com.example.myapplication.data.workout.FirestoreWorkoutRepository
import com.google.firebase.auth.ktx.auth
import com.google.firebase.ktx.Firebase
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.LocalTime
import java.util.concurrent.TimeUnit

/**
 * StreakReminderWorker — vsak dan ob 20:00 preveri, ali je vadba opravljena.
 *
 * Logika:
 * - Če je danes REST dan → ne pošlje notifikacije (streak bo +1 avtomatično ob polnoči)
 * - Če je danes WORKOUT dan in je vadba že opravljena → ne pošlje notifikacije
 * - Če je danes WORKOUT dan in vadba NI opravljena → pošlje motivacijsko notifikacijo
 *
 * Motivacijska sporočila se personalizirajo glede na:
 * - Trenutni streak
 * - Cilj (goal) iz plana
 * - Dan v planu
 */
class StreakReminderWorker(
    private val context: Context,
    workerParams: WorkerParameters
) : CoroutineWorker(context, workerParams) {

    private data class ReminderContext(
        val streak: Int,
        val planDay: Int,
        val waterMl: Int,
        val consumedCalories: Int,
        val burnedCalories: Int,
        val streakFreezes: Int,
        val currentHour: Int
    )

    companion object {
        private const val TAG = "StreakReminderWorker"
        private const val WORK_NAME = "streak_reminder_20h"
        const val CHANNEL_ID = "streak_reminder_channel"
        private const val NOTIFICATION_ID = 1001

        /**
         * Načrtuje opomnik za danes ob 20:00.
         * Kliči ob loginu in ob zagonu aplikacije.
         */
        fun scheduleForToday(context: Context) {
            val now = LocalDateTime.now()
            val targetTime = LocalDateTime.of(now.toLocalDate(), LocalTime.of(20, 0))

            // Če je 20:00 danes že minila, načrtuj za jutri ob 20:00
            val finalTarget = if (now.isBefore(targetTime)) targetTime
                             else targetTime.plusDays(1)

            val delayMs = java.time.Duration.between(now, finalTarget).toMillis()
            val delayMinutes = if (delayMs > 0) delayMs / 60000 else 1L

            val request = OneTimeWorkRequestBuilder<StreakReminderWorker>()
                .setInitialDelay(delayMinutes, TimeUnit.MINUTES)
                .build()

            WorkManager.getInstance(context)
                .enqueueUniqueWork(WORK_NAME, ExistingWorkPolicy.REPLACE, request)

            Log.d(TAG, "Scheduled streak reminder in ${delayMinutes}min (at $finalTarget)")
        }

        /**
         * Ustvari notification channel. Kliči ob zagonu aplikacije.
         */
        fun createNotificationChannel(context: Context) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Streak Reminders",
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Daily reminder to complete your workout and keep your streak alive"
                enableVibration(true)
            }
            val manager = context.getSystemService(NotificationManager::class.java)
            manager.createNotificationChannel(channel)
        }
    }

    override suspend fun doWork(): Result {
        // Preveri ali je uporabnik prijavljen
        val currentUser = Firebase.auth.currentUser
        if (currentUser == null || currentUser.email == null) {
            Log.d(TAG, "No user logged in — skipping reminder")
            scheduleForTomorrow()
            return Result.success()
        }

        val email = currentUser.email.orEmpty()
        val userProfile = UserProfileManager.loadProfile(email)

        // --- 1. QUIET HOURS PREVERBA (na podlagi uporabnikovih nastavitev) ---
        try {
            val now = LocalTime.now()
            val startParts = userProfile.quietHoursStart.split(":")
            val endParts = userProfile.quietHoursEnd.split(":")
            if (startParts.size == 2 && endParts.size == 2) {
                val start = LocalTime.of(startParts[0].toInt(), startParts[1].toInt())
                val end = LocalTime.of(endParts[0].toInt(), endParts[1].toInt())

                val inQuietHours = if (start.isBefore(end)) {
                    now.isAfter(start) && now.isBefore(end)
                } else {
                    now.isAfter(start) || now.isBefore(end)
                }

                if (inQuietHours) {
                    Log.d(TAG, "Current time is within quiet hours (${userProfile.quietHoursStart}-${userProfile.quietHoursEnd}) — skipping reminder")
                    scheduleForTomorrow()
                    return Result.success()
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error parsing quiet hours: ${e.message}")
        }

        // --- 2. PREVERI NASTAVITVE OBNOVITEV (Mute) ---
        if (userProfile.muteStreakReminders) {
            Log.d(TAG, "User muted streak reminders — skipping")
            scheduleForTomorrow()
            return Result.success()
        }

        // --- 3. PREBERI PODATKE O VADBI IN STREAKU ---
        val prefs = context.getSharedPreferences("bm_prefs", Context.MODE_PRIVATE)
        val todayIsRest = prefs.getBoolean("today_is_rest", false)
        val lastWorkoutEpoch = prefs.getLong("last_workout_epoch", 0L)
        val workoutDoneToday = if (lastWorkoutEpoch == 0L) false
            else LocalDate.ofEpochDay(lastWorkoutEpoch) == LocalDate.now()
        val currentStreak = prefs.getInt("streak_days", 0)
        val planDay = prefs.getInt("plan_day", 1)
        val reminderContext = loadReminderContext(currentStreak, planDay)

        Log.d(TAG, "Reminder check: todayIsRest=$todayIsRest, workoutDone=$workoutDoneToday, streak=$currentStreak")

        // --- 4. ODLOČITEV KAJ NAREDITI NA PODLAGI STANJA ---
        when {
            todayIsRest -> {
                // Rest dan — ni potreben opomnik
                Log.d(TAG, "Today is rest day — no reminder needed")
            }
            workoutDoneToday -> {
                // Vadba že opravljena — pošlji čestitko
                sendCongratulationsNotification(reminderContext)
            }
            else -> {
                // Vadba še ni opravljena — pošlji opomnik
                sendReminderNotification(reminderContext)
            }
        }

        // --- 5. NAČRTUJ ZA JUTRI OB 20:00 ---
        scheduleForTomorrow()

        return Result.success()
    }

    private fun loadReminderContext(streak: Int, planDay: Int): ReminderContext {
        val dateKey = LocalDate.now().toString()
        val waterMl = context.getSharedPreferences("water_cache", Context.MODE_PRIVATE)
            .getInt("water_$dateKey", 0)
        val consumedCalories = context.getSharedPreferences("calories_cache", Context.MODE_PRIVATE)
            .getInt("calories_$dateKey", 0)
        val burnedCalories = context.getSharedPreferences("burned_cache", Context.MODE_PRIVATE)
            .getInt("burned_$dateKey", 0)

        val email = Firebase.auth.currentUser?.email
        // --- 6. PREBERI ŠTEVILO ZAMRZOVANJ (FROZEN DAYS) ---
        val streakFreezes = try {
            runCatching { UserProfileManager.loadProfile(email ?: "").streakFreezes }.getOrDefault(0)
        } catch(e:Exception) {
            0
        }

        return ReminderContext(
            streak = streak,
            planDay = planDay,
            waterMl = waterMl,
            consumedCalories = consumedCalories,
            burnedCalories = burnedCalories,
            streakFreezes = streakFreezes,
            currentHour = LocalDateTime.now().hour
        )
    }

    private fun sendReminderNotification(ctx: ReminderContext) {
        // A/B test determination based on simple hash of user ID or device time if no user
        val uid = Firebase.auth.currentUser?.uid ?: ""
        val toneVariant = if (uid.isNotEmpty()) Math.abs(uid.hashCode()) % 3 else 0
        Log.d(TAG, "Notification Tone Variant selected: $toneVariant")

        val title = getReminderTitle(ctx, toneVariant)
        val message = getReminderMessage(ctx, toneVariant)

        sendNotification(title, message, isReminder = true)
        Log.d(
            TAG,
            "Sent contextual reminder: streak=${ctx.streak}, water=${ctx.waterMl}, calories=${ctx.consumedCalories}, burned=${ctx.burnedCalories}, freezes=${ctx.streakFreezes}"
        )
    }

    private fun sendCongratulationsNotification(ctx: ReminderContext) {
        val uid = Firebase.auth.currentUser?.uid ?: ""
        val toneVariant = if (uid.isNotEmpty()) Math.abs(uid.hashCode()) % 3 else 0

        val title = " Great job today!"
        val message = when (toneVariant) {
            0 -> when { // Encouraging & Soft
                ctx.streak >= 30 -> "You're on a ${ctx.streak} day streak. So proud of your discipline! "
                ctx.streak >= 14 -> "Two weeks straight (${ctx.streak} days). You're doing amazing! ✨"
                ctx.streak >= 7 -> "One week down (${ctx.streak} days). Keep up the fantastic work! "
                ctx.waterMl < 1200 -> "You did great. Just remember to drink some water to recover better! "
                else -> "Workout done. Pat yourself on the back! "
            }
            1 -> when { // Strict & Coach
                ctx.streak >= 30 -> "Hit ${ctx.streak} days. Elite discipline. No excuses tomorrow. "
                ctx.streak >= 14 -> "14+ days (${ctx.streak}). Don't lose the momentum now. "
                ctx.streak >= 7 -> "7 days down. The real test starts now. Keep pushing. "
                ctx.waterMl < 1200 -> "Mission accomplished, but hydration is weak. Drink water. "
                else -> "Session logged. Get ready for the next one. ️‍♂️"
            }
            else -> when { // Default / Data driven
                ctx.streak >= 30 -> "You're on a ${ctx.streak} day streak and still consistent. Elite discipline. "
                ctx.streak >= 14 -> "Two weeks+ consistency (${ctx.streak} days). Keep this momentum! "
                ctx.streak >= 7 -> "Week streak secured (${ctx.streak} days). Nice execution today. ⭐"
                ctx.waterMl < 1200 -> "Workout done. Add some hydration before sleep to recover better. "
                else -> "Workout done and streak alive. Great finish for today. "
            }
        }

        sendNotification(title, message, isReminder = false)
        Log.d(TAG, "Sent congratulations notification: streak=${ctx.streak}")
    }

    private fun getReminderTitle(ctx: ReminderContext, toneVariant: Int): String {
        val isLate = ctx.currentHour >= 21
        return when (toneVariant) {
            0 -> when { // Encouraging
                 ctx.streak >= 14 && ctx.streakFreezes == 0 -> "Don't break your ${ctx.streak}-day streak! "
                 ctx.waterMl < 600 -> "Let's drink some water! "
                 ctx.consumedCalories < 600 && isLate -> "Time for a small meal! "
                 ctx.streak == 0 -> "Ready to start a new streak? ✨"
                 ctx.streak >= 7 -> "Your ${ctx.streak}-day streak is beautiful! "
                 ctx.streak >= 3 -> "Keep your momentum going! "
                 else -> "You can do this workout! ❤️"
            }
            1 -> when { // Strict Coach
                 ctx.streak >= 14 && ctx.streakFreezes == 0 -> " ${ctx.streak} days at risk. Move!"
                 ctx.waterMl < 600 -> "Hydrate immediately. "
                 ctx.consumedCalories < 600 && isLate -> "Fuel up. No excuses. "
                 ctx.streak == 0 -> "Zero streak. Change that now. ⚡"
                 ctx.streak >= 7 -> "Protect your ${ctx.streak}-day streak or lose it. "
                 ctx.streak >= 3 -> "Don't get lazy now. ⏱️"
                 else -> "Time to work out! Go! ️"
            }
            else -> when { // Default
                ctx.streak >= 14 && ctx.streakFreezes == 0 -> " ${ctx.streak}-day streak at risk"
                ctx.waterMl < 600 -> " Hydrate + train"
                ctx.consumedCalories < 600 && isLate -> "️ Fuel up and finish your workout"
                ctx.streak == 0 -> "⚡ Start your streak today"
                ctx.streak >= 7 -> " Protect your ${ctx.streak}-day streak"
                ctx.streak >= 3 -> "⏱️ Keep the streak alive"
                else -> "️ Time to work out!"
            }
        }
    }

    private fun getReminderMessage(ctx: ReminderContext, toneVariant: Int): String {
        val week = ((ctx.planDay - 1) / 7) + 1
        val dayInWeek = ((ctx.planDay - 1) % 7) + 1
        val dayContext = "Week $week, Day $dayInWeek"

        val freezeContext = if (ctx.streakFreezes > 0) {
            "You still have ${ctx.streakFreezes} streak freeze${if (ctx.streakFreezes == 1) "" else "s"}, but use it only when necessary."
        } else {
            "No streak freeze available today, so this session matters."
        }

        return when (toneVariant) {
            0 -> when { // Extrinsic / Friendly
                ctx.waterMl < 600 -> "Your water intake is quite low (${ctx.waterMl} ml). Please hydrate and then try a quick workout. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "Today is the perfect day to start a new streak. Even 15 min is enough! ($dayContext)"
                else -> "Take some time for yourself today. Your daily workout awaits. ($dayContext)"
            }
            1 -> when { // Intrinsic / Aggressive
                ctx.waterMl < 600 -> "Low hydration (${ctx.waterMl} ml) ruins performance. Drink up and get the work done. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "A streak of 0 isn't progress. Put the work in today. ($dayContext)"
                else -> "Discipline over motivation. Go finish your session. ($dayContext)"
            }
            else -> when { // Default
                ctx.waterMl < 600 -> "Hydration is low (${ctx.waterMl} ml). Drink water first, then finish a short workout. $freezeContext ($dayContext)"
                ctx.consumedCalories < 600 && ctx.currentHour >= 21 -> "You logged only ${ctx.consumedCalories} kcal so far. Add a light meal and complete your session to recover well. $freezeContext ($dayContext)"
                ctx.burnedCalories >= 700 -> "You already burned ${ctx.burnedCalories} kcal today. Great activity - complete the planned workout to lock the streak. $freezeContext ($dayContext)"
                ctx.streak == 0 -> "Start your first streak day now. Even 20 minutes is enough to build momentum. ($dayContext)"
                ctx.streak >= 14 && ctx.streakFreezes == 0 -> "${ctx.streak} days of consistency are on the line. Complete today's workout to protect your run. ($dayContext)"
                ctx.streak >= 7 -> "One week+ streak in progress (${ctx.streak} days). Stay consistent tonight. ($dayContext)"
                ctx.streak >= 3 -> "Good rhythm so far (${ctx.streak} days). One more session keeps the chain going. ($dayContext)"
                else -> "Your daily workout is waiting. Quick session now makes tomorrow easier. ($dayContext)"
            }
        }
    }

    private fun sendNotification(title: String, message: String, isReminder: Boolean) {
        val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager

        // Ustvari channel če ne obstaja
        val channel = NotificationChannel(
            CHANNEL_ID,
            "Streak Reminders",
            NotificationManager.IMPORTANCE_DEFAULT
        ).apply {
            description = "Daily reminder to complete your workout and keep your streak alive"
            enableVibration(true)
        }
        notificationManager.createNotificationChannel(channel)

        // Intent za odprtje aplikacije
        val intent = Intent(context, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        val pendingIntent = PendingIntent.getActivity(
            context, 0, intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        val notification = NotificationCompat.Builder(context, CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_popup_reminder)
            .setContentTitle(title)
            .setContentText(message)
            .setStyle(NotificationCompat.BigTextStyle().bigText(message))
            .setContentIntent(pendingIntent)
            .setAutoCancel(true)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .apply {
                if (isReminder) {
                    setVibrate(longArrayOf(0, 300, 100, 300))
                }
            }
            .build()

        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun scheduleForTomorrow() {
        val now = LocalDateTime.now()
        val tomorrow = now.toLocalDate().plusDays(1)
        val targetDateTime = LocalDateTime.of(tomorrow, LocalTime.of(20, 0))

        val delayMs = java.time.Duration.between(now, targetDateTime).toMillis()
        val delayMinutes = if (delayMs > 0) delayMs / 60000 else 1L

        val request = OneTimeWorkRequestBuilder<StreakReminderWorker>()
            .setInitialDelay(delayMinutes, TimeUnit.MINUTES)
            .build()

        WorkManager.getInstance(context)
            .enqueueUniqueWork(WORK_NAME, ExistingWorkPolicy.REPLACE, request)

        Log.d(TAG, "Scheduled next reminder in ${delayMinutes}min (at $targetDateTime)")
    }
}

package com.example.myapplication

import org.junit.Test
import org.junit.Assert.*
import java.io.File

/**
 * ARHITEKTURNI TESTI — zagotavljajo da AI popravki ne pokvari ključnih invariant.
 *
 * Zaženemo z: ./gradlew test
 * Ko test pade → točno vidiš KAJ je pokvarjeno, brez ročnega iskanja.
 *
 * TESTI:
 *  1. BadgeConsistencyTest  — vsak badge ID v BadgeDefinitions mora imeti case v getBadgeProgress
 *  2. FirestoreRoutingTest  — nobena kt datoteka ne sme pisati direktno na document(email) ali document(uid) za profil
 *  3. DeprecatedXPTest      — addXPWithCallback se ne sme klicati nikjer (razen v sami definiciji)
 */
class ArchitectureTest {

    private val srcDir = File("src/main/java/com/example/myapplication")

    // ─── Pomožne funkcije ──────────────────────────────────────────────────────

    /** Vrne vse .kt datoteke rekurzivno */
    private fun allKtFiles(): List<File> =
        srcDir.walkTopDown().filter { it.isFile && it.extension == "kt" }.toList()

    /** Vrne vse vrstice vseh .kt datotek z imenom datoteke */
    private fun allLines(): List<Pair<String, String>> =
        allKtFiles().flatMap { f -> f.readLines().map { f.name to it } }

    /** Beri vsebino posamezne datoteke */
    private fun readFile(relativePath: String): String {
        val f = File("src/main/java/com/example/myapplication/$relativePath")
        return if (f.exists()) f.readText() else ""
    }

    // ─── TEST 1: Badge konsistentnost ──────────────────────────────────────────

    /**
     * Vsak badge ID definiran v BadgeDefinitions.ALL_BADGES mora imeti
     * ustrezen `case` v AchievementStore.getBadgeProgress().
     *
     * Zakaj: če badge ID manjka v getBadgeProgress(), vrne 0 → badge se nikoli ne odklene.
     */
    @Test
    fun `vsak badge ID v BadgeDefinitions mora imeti case v getBadgeProgress`() {
        val badgeDefsContent = readFile("data/BadgeDefinitions.kt")
        val achievementContent = readFile("persistence/AchievementStore.kt")

        assertTrue(
            "BadgeDefinitions.kt ne obstaja ali je prazna",
            badgeDefsContent.isNotBlank()
        )
        assertTrue(
            "AchievementStore.kt ne obstaja ali je prazna",
            achievementContent.isNotBlank()
        )

        // Izvleci vse badge ID-je iz BadgeDefinitions (id = "xxx" vzorec)
        val badgeIdRegex = Regex("""id\s*=\s*"([^"]+)"""")
        val definedIds = badgeIdRegex.findAll(badgeDefsContent)
            .map { it.groupValues[1] }
            .toList()

        assertTrue("BadgeDefinitions ne vsebuje nobenih badge ID-jev", definedIds.isNotEmpty())

        // Izvleci vse ID-je ki so pokriti v getBadgeProgress when-bloku
        val coveredIds = mutableSetOf<String>()
        val quotedIdRegex = Regex(""""([^"]+)"""")
        var inGetBadgeProgress = false
        var braceDepth = 0

        for (line in readFile("persistence/AchievementStore.kt").lines()) {
            if (line.contains("fun getBadgeProgress")) {
                inGetBadgeProgress = true
                braceDepth = 0
            }
            if (inGetBadgeProgress) {
                braceDepth += line.count { it == '{' } - line.count { it == '}' }
                quotedIdRegex.findAll(line).forEach { coveredIds.add(it.groupValues[1]) }
                if (braceDepth <= 0 && line.contains("}")) inGetBadgeProgress = false
            }
        }

        // Preveri da vsak definiran ID ima case
        val missing = definedIds.filter { it !in coveredIds }
        assertTrue(
            "Badge ID-ji NISO pokriti v getBadgeProgress() → ne bodo nikoli odklenjeni:\n" +
                    missing.joinToString("\n") { "  - \"$it\"" },
            missing.isEmpty()
        )
    }

    // ─── TEST 2: Firestore routing ─────────────────────────────────────────────

    /**
     * Nobena datoteka ne sme pisati .set() ali .update() direktno na
     * collection("users").document(<SPREMENLJIVKA>) — razen:
     *   - FirestoreHelper.kt (tam je to legalno — to JE resolver)
     *   - UserPreferences.kt vrstica z deleteUserData (tam je to namerno za brisanje)
     *   - ProfileStore.kt searchPublicProfiles (bere javne profile — ok)
     *
     * Bere samo — get(), addSnapshotListener() je ok (query, ne write).
     * Piše — set(), update(), add() na document(<var>) je napaka.
     */
    @Test
    fun `noben direkten Firestore write na document z spremenljivko razen FirestoreHelper`() {
        val allowedFiles = setOf(
            "FirestoreHelper.kt",   // To JE resolver — tu je to ok
            "UserPreferences.kt",   // deleteUserData — namerno briše stare dokumente
            "ProfileStore.kt",      // searchPublicProfiles — bere javne profile
            "FollowStore.kt"        // follows kolekcija — ne users/profil
        )

        // Vzorec: .document(<karkoli>).set( ali .update( ali .add(
        // Iščemo WRITE operacije na document z spremenljivko (ne s fiksnim nizom)
        val writeOnVarDocRegex = Regex(
            """\.document\(\s*(?!"\w)([a-zA-Z_][a-zA-Z0-9_]*)\s*\)\s*\.(set|update|add)\s*\("""
        )

        val violations = mutableListOf<String>()

        allKtFiles()
            .filter { it.name !in allowedFiles }
            .forEach { file ->
                file.readLines().forEachIndexed { idx, line ->
                    if (writeOnVarDocRegex.containsMatchIn(line)) {
                        // Izključi komentarje
                        val stripped = line.trimStart()
                        if (!stripped.startsWith("//") && !stripped.startsWith("*")) {
                            violations.add("${file.name}:${idx + 1}: $line")
                        }
                    }
                }
            }

        assertTrue(
            "Direktni Firestore WRITE na document(<spremenljivka>) najden — " +
                    "uporabi FirestoreHelper.getCurrentUserDocRef() namesto tega:\n" +
                    violations.joinToString("\n"),
            violations.isEmpty()
        )
    }

    // ─── TEST 3: Deprecated addXPWithCallback ──────────────────────────────────

    /**
     * addXPWithCallback je označena @Deprecated.
     * Nobena datoteka je ne sme klicati — razen UserPreferences.kt (kjer je definirana).
     *
     * Zakaj: addXPWithCallback ne preveri badge-ev, ne beleži xp_history,
     * in ne gre nujno skozi FirestoreHelper.
     * Pravilna pot je AchievementStore.awardXP().
     */
    @Test
    fun `addXPWithCallback se ne sme klicati nikjer razen v definiciji`() {
        val violations = allLines()
            .filter { (fileName, line) ->
                fileName != "UserPreferences.kt" &&   // tu je definirana
                line.contains("addXPWithCallback") &&
                !line.trimStart().startsWith("//") &&
                !line.trimStart().startsWith("*")
            }
            .map { (fileName, line) -> "  $fileName: ${line.trim()}" }

        assertTrue(
            "addXPWithCallback se kliče na ${violations.size} mestih — " +
                    "zamenjaj z AchievementStore.awardXP():\n" +
                    violations.joinToString("\n"),
            violations.isEmpty()
        )
    }

    // ─── TEST 4: FirestoreHelper cache se počisti ob odjavi ───────────────────

    /**
     * Ko se uporabnik odjavi, mora biti FirestoreHelper.clearCache() poklican.
     * Brez tega stari cache ostane → naslednji uporabnik bere napačen dokument.
     */
    @Test
    fun `FirestoreHelper clearCache mora biti poklican ob odjavi`() {
        // Poišči vse datoteke kjer se kliče signOut
        val signOutFiles = allKtFiles().filter { f ->
            f.readText().contains("signOut()")
        }

        assertTrue(
            "Nobena datoteka ne kliče signOut() — preskoči ta test če sign out ni implementiran",
            signOutFiles.isNotEmpty() || true  // soft — ne fail če ni sign out
        )

        val violations = signOutFiles.filter { f ->
            val text = f.readText()
            text.contains("signOut()") && !text.contains("clearCache()")
        }

        assertTrue(
            "signOut() se kliče brez FirestoreHelper.clearCache() v:\n" +
                    violations.joinToString("\n") { "  ${it.name}" } +
                    "\n→ Po odjavi mora biti cache počiščen sicer naslednji login bere napačen dokument.",
            violations.isEmpty()
        )
    }

    // ─── TEST 5: Vsi XPSource case-i so definirani ────────────────────────────

    /**
     * Vsak XPSource.XYZ ki se kliče v kodi mora biti definiran v enum class XPSource.
     * Če dodaš nov klic z XPSource.NOVO_IME brez da dodaš v enum → compile napaka.
     * Ta test je redundanten za compile napake, ampak dokumentira namero.
     */
    @Test
    fun `vsi XPSource klici so definirani v enum`() {
        val xpSourceContent = readFile("data/UserAchievements.kt")
        assertTrue("UserAchievements.kt ne obstaja", xpSourceContent.isNotBlank())

        // Izvleci definirane XPSource vrednosti
        val enumRegex = Regex("""^\s{4}([A-Z_]+),?\s*(//.*)?\s*$""")
        var inEnum = false
        val definedSources = mutableSetOf<String>()
        for (line in xpSourceContent.lines()) {
            if (line.contains("enum class XPSource")) { inEnum = true; continue }
            if (inEnum) {
                if (line.contains("}")) { inEnum = false; continue }
                enumRegex.find(line)?.let { definedSources.add(it.groupValues[1]) }
            }
        }

        assertTrue("XPSource enum je prazen", definedSources.isNotEmpty())

        // Poišči vse klice XPSource.XXX v kodi
        val xpSourceCallRegex = Regex("""XPSource\.([A-Z_]+)""")
        val violations = mutableListOf<String>()

        allKtFiles()
            .filter { it.name != "UserAchievements.kt" }
            .forEach { file ->
                file.readLines().forEachIndexed { idx, line ->
                    xpSourceCallRegex.findAll(line).forEach { match ->
                        val sourceName = match.groupValues[1]
                        if (sourceName !in definedSources) {
                            violations.add("${file.name}:${idx + 1}: XPSource.$sourceName ni definiran v enum!")
                        }
                    }
                }
            }

        assertTrue(
            "Nedefiniran XPSource klic:\n" + violations.joinToString("\n"),
            violations.isEmpty()
        )
    }
}

